import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"香山公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/xiangshan.md","filePath":"parks/xiangshan.md","lastUpdated":1784773307000}'),n={name:"parks/xiangshan.md"};function d(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="香山公园" tabindex="-1">香山公园 <a class="header-anchor" href="#香山公园" aria-label="Permalink to &quot;香山公园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-UN1Y_14Heo0?w=1200" alt="香山公园"></p><blockquote><p>&quot;香山红叶红满天，层林尽染醉秋烟。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>香山公园位于北京市海淀区西郊，是一座具有皇家园林特色的山林公园。香山以其秀美的自然风光和丰富的历史文化闻名，尤以秋季红叶著称。香山公园占地面积约160公顷，最高峰海拔557米，是北京市民登高赏秋的首选之地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-18:30（旺季），6:00-18:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">10元（旺季），5元（淡季）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">4-6小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">秋季（10月中旬-11月上旬）</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁西郊线香山站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市海淀区香山买卖街40号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="金代始建" tabindex="-1">金代始建 <a class="header-anchor" href="#金代始建" aria-label="Permalink to &quot;金代始建&quot;">​</a></h3><p>香山在金代就已经是皇家园林。金世宗在此修建了香山寺，开启了香山的皇家园林历史。</p><h3 id="明清时期" tabindex="-1">明清时期 <a class="header-anchor" href="#明清时期" aria-label="Permalink to &quot;明清时期&quot;">​</a></h3><p>明清时期，香山得到了大规模的营建。乾隆皇帝在此修建了静宜园，使香山成为皇家园林的巅峰之作。</p><h4 id="重要事件" tabindex="-1">重要事件 <a class="header-anchor" href="#重要事件" aria-label="Permalink to &quot;重要事件&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1186年</td><td style="text-align:left;">金世宗修建香山寺</td></tr><tr><td style="text-align:left;">1745年</td><td style="text-align:left;">乾隆皇帝修建静宜园</td></tr><tr><td style="text-align:left;">1860年</td><td style="text-align:left;">英法联军焚毁静宜园</td></tr><tr><td style="text-align:left;">1956年</td><td style="text-align:left;">香山公园正式开放</td></tr><tr><td style="text-align:left;">1993年</td><td style="text-align:left;">香山公园被评为AAAA级景区</td></tr></tbody></table><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="香山红叶" tabindex="-1">香山红叶 <a class="header-anchor" href="#香山红叶" aria-label="Permalink to &quot;香山红叶&quot;">​</a></h3><p>香山红叶是香山公园最著名的景观，每年秋季吸引大量游客前来观赏。</p><h4 id="红叶观赏" tabindex="-1">红叶观赏 <a class="header-anchor" href="#红叶观赏" aria-label="Permalink to &quot;红叶观赏&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">树种</th><th style="text-align:left;">特点</th><th style="text-align:left;">最佳观赏时间</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>黄栌</strong></td><td style="text-align:left;">香山红叶的主体</td><td style="text-align:left;">10月中旬-11月上旬</td></tr><tr><td style="text-align:left;"><strong>枫树</strong></td><td style="text-align:left;">叶色鲜红</td><td style="text-align:left;">10月中旬-11月上旬</td></tr><tr><td style="text-align:left;"><strong>银杏</strong></td><td style="text-align:left;">叶色金黄</td><td style="text-align:left;">10月中旬-11月上旬</td></tr><tr><td style="text-align:left;"><strong>火炬树</strong></td><td style="text-align:left;">叶色火红</td><td style="text-align:left;">10月中旬-11月上旬</td></tr></tbody></table><h4 id="最佳观赏地点" tabindex="-1">最佳观赏地点 <a class="header-anchor" href="#最佳观赏地点" aria-label="Permalink to &quot;最佳观赏地点&quot;">​</a></h4><ul><li><strong>香炉峰</strong>：香山最高峰，俯瞰红叶全景</li><li><strong>玉华岫</strong>：黄栌最为集中的地方</li><li><strong>森玉笏</strong>：红叶与古建筑相映成趣</li><li><strong>流憩亭</strong>：俯瞰香山红叶的最佳位置</li></ul><h3 id="香炉峰" tabindex="-1">香炉峰 <a class="header-anchor" href="#香炉峰" aria-label="Permalink to &quot;香炉峰&quot;">​</a></h3><p>香炉峰是香山的最高峰，海拔557米，因形似香炉而得名。</p><h4 id="登顶路线" tabindex="-1">登顶路线 <a class="header-anchor" href="#登顶路线" aria-label="Permalink to &quot;登顶路线&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">路线</th><th style="text-align:left;">长度</th><th style="text-align:left;">难度</th><th style="text-align:left;">用时</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>北线</strong></td><td style="text-align:left;">约2.5公里</td><td style="text-align:left;">中等</td><td style="text-align:left;">约1.5小时</td></tr><tr><td style="text-align:left;"><strong>南线</strong></td><td style="text-align:left;">约2公里</td><td style="text-align:left;">较易</td><td style="text-align:left;">约1小时</td></tr><tr><td style="text-align:left;"><strong>中线</strong></td><td style="text-align:left;">约2.2公里</td><td style="text-align:left;">中等</td><td style="text-align:left;">约1小时</td></tr></tbody></table><h3 id="碧云寺" tabindex="-1">碧云寺 <a class="header-anchor" href="#碧云寺" aria-label="Permalink to &quot;碧云寺&quot;">​</a></h3><p>碧云寺位于香山东麓，是一座历史悠久的佛教寺院。</p><h4 id="主要建筑" tabindex="-1">主要建筑 <a class="header-anchor" href="#主要建筑" aria-label="Permalink to &quot;主要建筑&quot;">​</a></h4><ul><li><strong>山门</strong>：碧云寺的正门</li><li><strong>天王殿</strong>：供奉四大天王</li><li><strong>大雄宝殿</strong>：主殿，供奉释迦牟尼</li><li><strong>罗汉堂</strong>：供奉五百罗汉</li><li><strong>金刚宝座塔</strong>：明代建筑，是碧云寺的标志性建筑</li></ul><h3 id="卧佛寺" tabindex="-1">卧佛寺 <a class="header-anchor" href="#卧佛寺" aria-label="Permalink to &quot;卧佛寺&quot;">​</a></h3><p>卧佛寺位于香山东麓，因寺内供奉一尊巨大的卧佛而得名。</p><h4 id="主要看点" tabindex="-1">主要看点 <a class="header-anchor" href="#主要看点" aria-label="Permalink to &quot;主要看点&quot;">​</a></h4><ul><li><strong>卧佛</strong>：长5米余的铜铸卧佛</li><li><strong>千年古树</strong>：寺内有多棵千年古树</li><li><strong>古建筑</strong>：保存完好的古建筑群</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>红叶观赏路线（约4小时）</strong>：</p><p>东门 → 勤政殿 → 玉华岫 → 森玉笏 → 香雾窟 → 香炉峰 → 碧云寺 → 卧佛寺 → 西门</p><p><strong>登山路线（约3小时）</strong>：</p><p>北门 → 香炉峰 → 香雾窟 → 森玉笏 → 玉华岫 → 勤政殿 → 东门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>红叶季</strong>：10月中旬至11月上旬是最佳观赏期，但人很多，建议早去</li><li><strong>登山准备</strong>：穿舒适的鞋子，带足饮水</li><li><strong>拍照位置</strong>：香炉峰、玉华岫、森玉笏都是绝佳拍照点</li><li><strong>交通建议</strong>：红叶季建议乘坐公共交通，自驾停车困难</li><li><strong>周边游览</strong>：可以与碧云寺、卧佛寺一起游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">西郊线香山站，步行约10分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">563、318、331、360、698路香山公园站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;香山公园&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">碧云寺</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">佛教寺院</td></tr><tr><td style="text-align:left;">卧佛寺</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">佛教寺院</td></tr><tr><td style="text-align:left;">北京植物园</td><td style="text-align:center;">约2公里</td><td style="text-align:left;">植物观赏</td></tr><tr><td style="text-align:left;">颐和园</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">玉泉山</td><td style="text-align:center;">约3公里</td><td style="text-align:left;">名胜古迹</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市海淀区香山买卖街40号 ** 地铁**：西郊线香山站 <strong>📞 电话</strong>：010-62591155 <strong>🌐 官网</strong>：<a href="http://www.xiangshanpark.com.cn" target="_blank" rel="noreferrer">www.xiangshanpark.com.cn</a></p><p><strong>💡 Tips</strong>：香山红叶季人非常多，建议早上7点前到达，避开人流高峰。登顶香炉峰需要一定体力，建议量力而行。</p>',48)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
